head.b:skin:
:root {
    --primary: #e74c3c;
    --accent-soft: rgba(231, 76, 60, 0.08);
    --bg-body: #f1f5f9;
    --card-bg: #ffffff;
    --text-main: #0f172a;
    --text-muted: #64748b;
    --glass: rgba(255, 255, 255, 0.85);
    --border: rgba(0, 0, 0, 0.05);
    --shadow: 0 10px 30px -10px rgba(0, 0, 0, 0.1);
}

body {
    background-color: var(--bg-body);
    font-family: 'Inter', 'Hind Siliguri', sans-serif;
    margin: 0; padding: 0;
    color: var(--text-main);
    overflow-x: hidden;
}

/* Smart Sticky Header */
header {
    background: var(--glass);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border-bottom: 1px solid var(--border);
    padding: 15px 0;
    position: sticky; top: 0; z-index: 1000;
}

.container { max-width: 1200px; margin: 0 auto; padding: 0 20px; }

.header-content { display: flex; justify-content: space-between; align-items: center; }
.logo-text { font-size: 24px; font-weight: 800; color: var(--primary); text-decoration: none; letter-spacing: -0.5px; }

/* Search Section */
.hero-section { padding: 50px 0 20px; text-align: center; }
.hero-section h1 { font-size: 32px; font-weight: 800; margin-bottom: 25px; font-family: 'Hind Siliguri'; }

.search-wrapper { position: relative; max-width: 600px; margin: 0 auto; }
#searchBox {
    width: 100%; padding: 18px 30px; border-radius: 50px; border: 1px solid var(--border);
    box-shadow: var(--shadow); outline: none; font-size: 16px;
    font-family: 'Hind Siliguri'; transition: all 0.3s;
}
#searchBox:focus { border-color: var(--primary); box-shadow: 0 0 0 4px var(--accent-soft); }

/* Ad Slots Management */
.ad-container { margin: 20px auto; max-width: 1000px; }
.ad-placeholder { 
    background: #fff; border: 1px dashed #cbd5e1; border-radius: 16px;
    min-height: 90px; display: flex; align-items: center; justify-content: center;
    position: relative; overflow: hidden;
}
.ad-placeholder::after { content: 'ADVERTISEMENT'; position: absolute; top: 5px; right: 10px; font-size: 9px; color: #94a3b8; }

/* Layout Grid */
.page-layout { display: grid; grid-template-columns: 1fr 300px; gap: 30px; margin-top: 30px; }

/* Category Wise Sections */
.category-block { margin-bottom: 40px; }
.category-header { 
    display: flex; align-items: center; gap: 15px; margin-bottom: 20px;
    padding-bottom: 10px; border-bottom: 2px solid var(--border);
}
.category-header h2 { font-size: 20px; font-weight: 700; font-family: 'Hind Siliguri'; margin: 0; }
.category-header .badge { background: var(--primary); color: #fff; font-size: 11px; padding: 3px 8px; border-radius: 6px; }

.bento-grid {
    display: grid; grid-template-columns: repeat(auto-fill, minmax(160px, 1fr)); gap: 18px;
}

/* Smart Bento Card */
.news-card {
    background: var(--card-bg); border-radius: 24px; padding: 25px 15px;
    text-align: center; border: 1px solid var(--border);
    transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
    cursor: pointer; box-shadow: 0 4px 6px -1px rgba(0,0,0,0.02);
    display: flex; flex-direction: column; align-items: center;
}

.news-card:hover {
    transform: translateY(-10px) scale(1.02);
    border-color: var(--primary);
    box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.05);
}

.news-card .icon-circle {
    width: 60px; height: 60px; background: #f8fafc; border-radius: 18px;
    display: flex; align-items: center; justify-content: center;
    margin-bottom: 15px; border: 1px solid var(--border);
}

.news-card img { width: 35px; height: 35px; border-radius: 8px; }

.news-card span {
    font-size: 15px; font-weight: 600; font-family: 'Hind Siliguri';
    color: var(--text-main); line-height: 1.4;
}

/* Professional Modal Viewer */
.viewer-overlay {
    position: fixed; top: 0; left: 0; width: 100%; height: 100%;
    background: rgba(15, 23, 42, 0.9); backdrop-filter: blur(8px);
    display: none; z-index: 2000; justify-content: center; align-items: center;
}

.viewer-content {
    width: 96%; height: 94%; background: #fff; border-radius: 28px;
    overflow: hidden; display: flex; flex-direction: column;
    box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
}

.viewer-bar {
    padding: 15px 25px; background: #fff; border-bottom: 1px solid #eee;
    display: flex; justify-content: space-between; align-items: center;
}

.viewer-bar .title-group { display: flex; align-items: center; gap: 10px; }
.viewer-bar h2 { font-size: 16px; margin: 0; font-family: 'Hind Siliguri'; color: var(--text-main); }

iframe#contentFrame { width: 100%; height: 100%; border: none; background: #fff; }

.btn-close { 
    background: #f1f5f9; color: var(--text-main); border: none; 
    padding: 10px 20px; border-radius: 12px; cursor: pointer; 
    font-weight: 700; transition: 0.2s;
}
.btn-close:hover { background: var(--primary); color: #fff; }

/* Responsive */
@media (max-width: 900px) {
    .page-layout { grid-template-columns: 1fr; }
    .side-ads { display: none; }
    .bento-grid { grid-template-columns: repeat(2, 1fr); gap: 12px; }
}

body.script:
function openReader(url, name) {
    const modal = document.getElementById('newsViewer');
    const frame = document.getElementById('contentFrame');
    const title = document.getElementById('viewerSiteTitle');

    title.innerText = name;
    frame.src = url;
    modal.style.display = 'flex';
    document.body.style.overflow = 'hidden';
}

function closeReader() {
    const modal = document.getElementById('newsViewer');
    const frame = document.getElementById('contentFrame');
    modal.style.display = 'none';
    frame.src = '';
    document.body.style.overflow = 'auto';
}

function searchNews() {
    let input = document.getElementById('searchBox').value.toLowerCase();
    let cards = document.getElementsByClassName('news-card');
    for (let i = 0; i < cards.length; i++) {
        let name = cards[i].innerText.toLowerCase();
        cards[i].style.display = name.includes(input) ? "flex" : "none";
    }
}
